ControlPropertyState.AutoRuleBindingString:
With(
    {
        ops:
            IfError(
                ParseJSON(
                    Substitute(
                        LookUp(
                            tbl_mrl_workorder,
                            ID = ThisItem.workorder.Id,
                            operations
                        ),
                        "'",
                        """"
                    )
                ),
                Blank()
            )
    },
    If(
        IsBlank(ops) || CountRows(ops) = 0,
        Blank(),
        IfError(
            Text( First(ops).operation_text ),
            Blank()
        )
    )
)

